### Configure React Router with BrowserRouter and Routes (TypeScript/React)

Source: https://github.com/clerk/clerk-docs/blob/main/docs/guides/development/declarative-mode.mdx

This example demonstrates how to set up React Router in declarative mode within `src/main.tsx`. It imports `BrowserRouter`, `Routes`, and `Route` from `react-router`, then wraps the `ClerkProvider` and the application's routes within a `<BrowserRouter>`. This structure defines the application's navigation paths, with a basic home route (`/`) rendering the `<App />` component, ensuring routing works seamlessly with Clerk's authentication.

```tsx
import { StrictMode } from 'react'
import { createRoot } from 'react-dom/client'
import { BrowserRouter, Routes, Route } from 'react-router'
import { ClerkProvider } from '@clerk/react-router'
import './index.css'
import App from './App.tsx'

// Import your Publishable Key
const PUBLISHABLE_KEY = import.meta.env.VITE_CLERK_PUBLISHABLE_KEY

if (!PUBLISHABLE_KEY) {
  throw new Error('Add your Clerk Publishable Key to the .env file')
}

createRoot(document.getElementById('root')!).render(
  <StrictMode>
    <BrowserRouter>
      <ClerkProvider publishableKey={PUBLISHABLE_KEY}>
        <Routes>
          <Route path="/" element={<App />} />
        </Routes>
      </ClerkProvider>
    </BrowserRouter>
  </StrictMode>,
)
```

--------------------------------

### Update ClerkProvider for Passkey Support in TypeScript

Source: https://github.com/clerk/clerk-docs/blob/main/docs/reference/expo/passkeys.mdx

Modify the root layout to import passkeys and pass them to the ClerkProvider component. This enables the experimental passkey features across your Expo application.

```tsx
import { ClerkProvider } from '@clerk/expo'
import { Slot } from 'expo-router'
import { tokenCache } from '@clerk/expo/token-cache'
import { passkeys } from '@clerk/expo/passkeys'

// Import your Publishable Key
const publishableKey = process.env.EXPO_PUBLIC_CLERK_PUBLISHABLE_KEY

if (!publishableKey) {
  throw new Error('Add your Clerk Publishable Key to the .env file')
}

export default function RootLayout() {
  return (
    <ClerkProvider
